#Generador de claves RSA
#Ejecutar una sola vez
from cryptography.hazmat.primitives.asymmetric.rsa import generate_private_key

clave_privada_aplicacion= generate_private_key(public_exponent=65537,key_size=2048)
clave_publica_aplicacion= clave_privada_aplicacion.public_key()

numeros_publicos_app= clave_publica_aplicacion.public_numbers()

n_app = numeros_publicos_app.n
e_app = numeros_publicos_app.e

numeros_privados_app = clave_privada_aplicacion.private_numbers()
d_app = numeros_privados_app.d

print("n de la app",n_app)
print("\ne de la app",e_app)
print("\nd de la app",d_app)

